public void getUserByName(GetUserByNameRo request, StreamObserver<UserInfo> responseObserver) {
    String name = request.getName();
    String possibleEmail = name + "@yottastudios.com";
    UserEntity userEntity = null;
    UserEntity userEntityByEmail = iUserService.getByEmail(possibleEmail);
    List<UserEntity> userEntities = iUserService.selectUsersByNicknameLike(name);
    UserEntity userEntityByNickName = CollectionUtils.isEmpty(userEntities) ? null : userEntities.get(0);
