    @Override
    public void createNode(CreateNodeRo request, StreamObserver<CreateNodeResult> responseObserver) {
        Long userId = request.getUserId();
        String spaceId = request.getSpaceId();
        String name = request.getName();
        Integer type = request.getType();
        NodeRelRequest nodeRelRequest = request.getExtra();
        String rootNodeId = iNodeService.getRootNodeIdBySpaceId(spaceId);
        NodeOpRo nodeOpRo = NodeOpRo.builder()
                .nodeName(name)
                .checkDuplicateName(false)
                .type(type)
                .parentId(rootNodeId)
                .build();
        if(null!=nodeRelRequest)
            nodeOpRo.setExtra(new NodeRelRo(nodeRelRequest.getDatasheetId(),
                    nodeRelRequest.getViewId(),nodeRelRequest.getViewName()));

        String nodeId = HolderContextUtil.execute(userId, spaceId, () -> iNodeService.createNode(userId, spaceId, nodeOpRo));

        CreateNodeResult result = CreateNodeResult.newBuilder()
                .setNodeId(nodeId)
                .build();

        responseObserver.onNext(result);
        responseObserver.onCompleted();
    }

