    @Override
    public void deleteNode(DeleteNodeRequest request, StreamObserver<BasicResult> responseObserver) {
        Integer code = DEFAULT_SUCCESS_CODE;
        String message = DEFAULT_SUCCESS_MESSAGE;
        long userId = request.getUserId();
        String nodeId = request.getNodeId();
        String spaceId = request.getSpaceId();
        Long memberId = iMemberService.getMemberIdByUserIdAndSpaceId(request.getUserId(), spaceId);
        if (memberId == null) {
            log.warn("user不存在,userId:{},spaceId:{}", userId, spaceId);
            code = DEFAULT_ERROR_CODE;
            message = DEFAULT_ERROR_MESSAGE;
        }else{
            log.warn("deleteNode,userId:{},spaceId:{},nodeId:{}", userId, spaceId,nodeId);
            HolderContextUtil.execute(userId, spaceId, () -> iNodeService.deleteById(spaceId, memberId, nodeId));
            spaceCapacityCacheService.del(spaceId);
        }
        BasicResult result = BasicResult.newBuilder()
                .setCode(code)
