    @Override
    public void replaceSpaceManager(ReplaceManagerRequest request,
                                    StreamObserver<ReplaceManagerResponse> responseObserver) {
        log.info("收到replaceSpaceManager请求，参数：{},{},{}", request.getSpaceId(), request.getUserId(), request.getOpUserId());
        ReplaceManagerResponse.Builder responseBuilder = ReplaceManagerResponse.newBuilder();

        try {
            String spaceId = request.getSpaceId();
            Long InviteUserId = request.getUserId();
            String email = request.getEmail();

            // 先判断userid是否在space中，假如不在，先把userid添加到space中
            Long userMemberId = iMemberService.getMemberIdByUserIdAndSpaceId(InviteUserId, spaceId);
            if (userMemberId == null) {
                List<Long> memberIds = iMemberService.emailInvitation(InviteUserId, spaceId, new ArrayList<>(List.of(email)));
                if (memberIds.isEmpty()) {
                    throw new RuntimeException("member error");
