    /**
     * 验证用户登录
     * @param request 登录验证请求
     * @param responseObserver 响应观察者
     */
    public void validateLogin(LoginValidateRequest request,
                              StreamObserver<LoginValidateResponse> responseObserver) {

        log.info("收到登录验证请求，用户名: {}", request.getUsername());

        try {
            // 获取请求参数
            String username = request.getUsername();
            String password = request.getPassword();

            // 参数验证
            if (username.trim().isEmpty()) {
                sendErrorResponse(responseObserver, "用户名或密码错误");
                return;
            }

            if (password.trim().isEmpty()) {
                sendErrorResponse(responseObserver, "用户名或密码错误");
                return;
            }

            UserEntity existedUser = userMapper.selectByEmail(username);
            if (existedUser == null){
                sendErrorResponse(responseObserver, "用户名或密码错误");
                return;
            }
            else{
                if (!passwordService.matches(password, existedUser.getPassword())){
                    sendErrorResponse(responseObserver, "用户名或密码错误");
                    return;
                }
            }

            // 调用业务服务验证用户
            Long userId = existedUser.getId();

            if (userId != null && userId > 0) {
                // 验证成功，返回用户ID
                LoginValidateResponse response = LoginValidateResponse.newBuilder()
                        .setUserId(userId)
                        .setMessage("登录验证成功")
                        .build();

                responseObserver.onNext(response);
                responseObserver.onCompleted();

                log.info("用户 {} 登录验证成功，用户ID: {}", username, userId);

            } else {
                // 验证失败
                sendErrorResponse(responseObserver, "用户名或密码错误");
                log.warn("用户 {} 登录验证失败", username);
            }

        } catch (Exception e) {
            log.error("处理登录验证请求时发生错误", e);
            sendErrorResponse(responseObserver, "系统内部错误");
        }
    }

    /**
     * 发送错误响应
     * @param responseObserver 响应观察者
     * @param errorMessage 错误消息
     */
    private void sendErrorResponse(StreamObserver<LoginValidateResponse> responseObserver,
                                   String errorMessage) {
        LoginValidateResponse response = LoginValidateResponse.newBuilder()
                .setUserId(0) // 0表示登录失败
                .setMessage(errorMessage)
                .build();

        responseObserver.onNext(response);
        responseObserver.onCompleted();
    }

    @Override
    public void exportLuckysheetToMinio(ExportLuckysheetToMinioRequest request,
                                        StreamObserver<ExportLuckysheetToMinioResult> responseObserver) {
        log.info("收到导出Luckysheet请求，nodeId: {}", request.getNodeId());

        ExportLuckysheetToMinioResult.Builder responseBuilder = ExportLuckysheetToMinioResult.newBuilder();

        try {
            String nodeId = request.getNodeId();

            if (nodeId.trim().isEmpty()) {
                responseBuilder.setSuccess(false)
                        .setMessage("nodeId不能为空");
                responseObserver.onNext(responseBuilder.build());
                responseObserver.onCompleted();
                return;
            }

            String nodeName = iNodeService.getNodeNameByNodeId(nodeId);
            if (nodeName == null || nodeName.trim().isEmpty()) {
                nodeName = "luckysheet_export";
            }


            List<JSONObject> sheets = jfGridFileGetService.getAllSheetByGridKey(nodeId, false);
            if (sheets == null || sheets.isEmpty()) {
                log.info("未找到Luckysheet数据，创建空Excel文件，nodeId: {}", nodeId);
                sheets = new ArrayList<>();
                JSONObject emptySheet = new JSONObject();
                emptySheet.put("name", "Sheet1");
                emptySheet.put("index", "0");
                emptySheet.put("order", 0);
                emptySheet.put("status", 1);
                emptySheet.put("row", 200);
                emptySheet.put("column", 26);
                emptySheet.put("celldata", new cn.hutool.json.JSONArray());
                JSONObject config = new JSONObject();
                config.put("borderInfo", new cn.hutool.json.JSONArray());
                emptySheet.put("config", config);

                sheets.add(emptySheet);
            }

            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            XlsUtil.exportXlsFile(baos, true, sheets);
            byte[] fileData = baos.toByteArray();

            String fileName = nodeName + ".xlsx";

            try (ByteArrayInputStream inputStream = new ByteArrayInputStream(fileData)) {
                AssetUploadResult uploadResult = assetService.uploadFileInRubbish(inputStream, fileData.length,
                    "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet");

                String resourceUrl = constProperties.getAssetDomain() + "/" + constProperties.getOssBucketByAsset().getBucketName();
                if (!resourceUrl.endsWith("/")) {
                    resourceUrl += "/";
                }
                String downloadUrl = resourceUrl + uploadResult.getToken();

                responseBuilder.setSuccess(true)
                           .setDownloadUrl(downloadUrl)
                           .setFileName(fileName)
                           .setMessage("导出成功");

                log.info("Luckysheet导出成功，nodeId: {}, downloadUrl: {}", nodeId, downloadUrl);
            }

        } catch (Exception e) {
            log.error("导出Luckysheet失败", e);
            responseBuilder.setSuccess(false)
                       .setMessage("导出失败: " + e.getMessage());
        }

        responseObserver.onNext(responseBuilder.build());
        responseObserver.onCompleted();
    }

