    @Override
    public void sendWorkspaceApplyNotify(SendWorkspaceApplyNotifyRequest request,
                                        StreamObserver<BasicResult> responseObserver) {
        List<Long> adminUserIds = request.getAdminUserIdsList();
        String message = request.getMessage();
        log.info("[1822-WorkspaceApply] sendNotify start adminCount={} messageLen={}",
                adminUserIds != null ? adminUserIds.size() : 0, message != null ? message.length() : 0);
        try {
            if (CollectionUtils.isEmpty(adminUserIds) || StringUtils.isBlank(message)) {
                log.warn("[1822-WorkspaceApply] sendNotify invalid adminEmpty={} messageBlank={}",
                        CollectionUtils.isEmpty(adminUserIds), StringUtils.isBlank(message));
                responseObserver.onNext(BasicResult.newBuilder().setCode(0).build());
                responseObserver.onCompleted();
                return;
            }
            List<UserEntity> users = userMapper.selectByIds(adminUserIds);
            if (CollectionUtils.isEmpty(users)) {
                log.warn("[1822-WorkspaceApply] sendNotify no users in DB adminCount={}", adminUserIds != null ? adminUserIds.size() : 0);
                responseObserver.onNext(BasicResult.newBuilder().setCode(0).build());
                responseObserver.onCompleted();
                return;
            }
            boolean isInternal = constProperties.isInternalNetwork();
            if (isInternal) {
                java.util.Set<String> emails = new java.util.HashSet<>();
                for (UserEntity user : users) {
                    if (StringUtils.isNotBlank(user.getEmail())) {
                        emails.add(user.getEmail());
                    }
                }
                if (emails.isEmpty()) {
                    log.warn("[1822-WorkspaceApply] sendNotify no valid emails adminCount={} userCount={}", adminUserIds.size(), users.size());
                } else {
                    mattermostMessageService.sendMessageByEmails(emails, message);
                    log.info("[1822-WorkspaceApply] sendNotify SUCCESS channel=mattermost recipients={}", emails.size());
                }
            } else {
                java.util.Set<String> nicknames = new java.util.HashSet<>();
                for (UserEntity user : users) {
                    if (StringUtils.isNotBlank(user.getNickName())) {
                        nicknames.add(user.getNickName());
                    }
                }
                if (nicknames.isEmpty()) {
                    log.warn("[1822-WorkspaceApply] sendNotify no valid nicknames adminCount={} userCount={}", adminUserIds.size(), users.size());
                } else {
                    knockMessageService.sendKnockMessage(nicknames, message);
                    log.info("[1822-WorkspaceApply] sendNotify SUCCESS channel=knock recipients={}", nicknames.size());
                }
            }
            responseObserver.onNext(BasicResult.newBuilder().setCode(0).build());
        } catch (Exception e) {
            log.error("[1822-WorkspaceApply] ERROR sendNotify error={}", e.getMessage(), e);
            responseObserver.onNext(BasicResult.newBuilder().setCode(-1).setMessage(e.getMessage()).build());
        }
        responseObserver.onCompleted();
    }

