        try {
            if (request.getIsRead()) {
                playerNotificationMapper.updateReadIsTrueByIds(new String[]{String.valueOf(request.getNotificationId())});
            } else {
                playerNotificationMapper.updateReadIsFalseByIdAndToUser(
                        request.getNotificationId(), request.getToUserId());
            }
            responseObserver.onNext(com.apitable.integration.grpc.BasicResult.newBuilder()
                    .setCode(0).build());
        } catch (Exception e) {
            log.error("[1822-notify] setNotificationRead failed notificationId={} error={}",
                    request.getNotificationId(), e.getMessage(), e);
            responseObserver.onNext(com.apitable.integration.grpc.BasicResult.newBuilder()
                    .setCode(-1).setMessage(e.getMessage()).build());
        }
        responseObserver.onCompleted();
    }

    /**
     * 根据 teamIds 批量查询对应的 unitId.
     * 查询 apitable_unit 表: unit_type=1(team), unit_ref_id=teamId
     */
    @Override
    public void getUnitIdsByTeamIds(GetUnitIdsByTeamIdsRequest request,
                                   StreamObserver<GetUnitIdsByTeamIdsResponse> responseObserver) {
        List<Long> teamIds = request.getTeamIdsList();
        log.info("[lbl][2093-权限优化][gRPC][QUERY] getUnitIdsByTeamIds 收到请求, spaceId={}, teamCount={}", request.getSpaceId(), teamIds.size());

        try {
            List<TeamUnitIdMapping> mappings = new ArrayList<>();
            if (!CollectionUtils.isEmpty(teamIds)) {
                // 处理 teamId=0（根小组，apitable 的 loadMemberTeamTree 会将根小组 teamId 置为 0）
                List<Long> realTeamIds = new ArrayList<>(teamIds);
                boolean hasRootTeam = realTeamIds.remove(0L);
                Long rootTeamId = null;
                if (hasRootTeam) {
                    rootTeamId = iTeamService.getRootTeamId(request.getSpaceId());
                    if (rootTeamId != null) {
                        realTeamIds.add(rootTeamId);
                    }
                }

                if (!realTeamIds.isEmpty()) {
                    List<UnitEntity> units = unitService.getByRefIds(realTeamIds);
                    for (UnitEntity unit : units) {
                        // unit_type=1 表示 team
                        if (unit.getUnitType() != null && unit.getUnitType() == 1) {
                            // 根小组返回 teamId=0，保持与调用方一致
                            long returnTeamId = (hasRootTeam && unit.getUnitRefId().equals(rootTeamId))
                                    ? 0L : unit.getUnitRefId();
                            mappings.add(TeamUnitIdMapping.newBuilder()
                                    .setTeamId(returnTeamId)
                                    .setUnitId(unit.getId())
                                    .build());
                        }
                    }
                }
            }

            log.info("[lbl][2093-权限优化][gRPC][QUERY] getUnitIdsByTeamIds 完成, spaceId={}, teamCount={}, mappedCount={}", request.getSpaceId(), teamIds.size(), mappings.size());
            GetUnitIdsByTeamIdsResponse response = GetUnitIdsByTeamIdsResponse.newBuilder()
                    .addAllMappings(mappings)
                    .build();
            responseObserver.onNext(response);
            responseObserver.onCompleted();
        } catch (Exception e) {
            log.error("[lbl][2093-权限优化][gRPC][QUERY] getUnitIdsByTeamIds 失败, spaceId={}, teamCount={}", request.getSpaceId(), teamIds.size(), e);
            responseObserver.onError(e);
        }
    }

}

