    @Override
    public void renameSpace(RenameSpaceRequest request, StreamObserver<BasicResult> responseObserver) {
        Integer code = DEFAULT_SUCCESS_CODE;
        String message = DEFAULT_SUCCESS_MESSAGE;

        try {
            Long userId = request.getUserId();
            String spaceId = request.getSpaceId();
            String newSpaceName = request.getNewSpaceName();

            SpaceUpdateOpRo spaceUpdateOpRo = SpaceUpdateOpRo.builder()
                .name(newSpaceName)
                .build();

            spaceService.updateSpace(userId, spaceId, spaceUpdateOpRo);

            log.info("Successfully renamed space, userId:{}, spaceId:{}, newName:{}", userId, spaceId, newSpaceName);
        } catch (Exception e) {
            log.error("Failed to rename space, request:{}", request, e);
            code = DEFAULT_ERROR_CODE;
            message = "Failed to rename space: " + e.getMessage();
        }

        BasicResult result = BasicResult.newBuilder()
                .setCode(code)
                .setMessage(message)
                .setSuccess(code.equals(DEFAULT_SUCCESS_CODE))
                .build();
        responseObserver.onNext(result);
        responseObserver.onCompleted();
    }

