    @Override
    public void copyFile(CopyFileRequest request, StreamObserver<CopyFileResponse> responseObserver) {
        log.info("收到copyFile请求，参数：{},{},{}", request.getSpaceId(), request.getUserId(), request.getNodeId());
        CopyFileResponse.Builder responseBuilder = CopyFileResponse.newBuilder();
        try{
            Long userId = request.getUserId();
            NodeCopyOpRo nodeOpRo = new  NodeCopyOpRo();
            nodeOpRo.setNodeId(request.getNodeId());
            nodeOpRo.setData(true);
            NodeCopyEffectDTO copyEffect = iNodeService.copy(userId, nodeOpRo);
            if (copyEffect == null){
                throw new RuntimeException("copy error");
            }
            copyEffect.setUserId(userId);
            // iNodeService.nodeCopyChangeset(copyEffect);
            // publish space audit events
            AuditSpaceEvent.AuditSpaceArg arg =
                    AuditSpaceEvent.AuditSpaceArg.builder().action(AuditSpaceAction.COPY_NODE).userId(userId)
                            .nodeId(copyEffect.getCopyNodeId())
                            .info(JSONUtil.createObj().set(AuditConstants.SOURCE_NODE_ID, nodeOpRo.getNodeId())
                                    .set(AuditConstants.RECORD_COPYABLE, nodeOpRo.getData())).build();
            SpringContextHolder.getApplicationContext().publishEvent(new AuditSpaceEvent(this, arg));
            // The new node inherits parent node permissions by default
            // copy robots
            CopyAllRobotsRequest copyAllRobotsRequest = new CopyAllRobotsRequest();
            copyAllRobotsRequest.setOriginalResourceId(nodeOpRo.getNodeId());
            copyAllRobotsRequest.setNewResourceId(copyEffect.getCopyNodeId());
            copyAllRobotsRequest.setUserId(userId.toString());
            ResponseData<Void> copyAllRobotsResponse = apitableOpenapiService.copyAllRobotsToNewResource(copyAllRobotsRequest);
            if (!copyAllRobotsResponse.getSuccess()) {
                log.error("Failed to copy robots from original node to new node.");
            }
            // 组装返回值
            responseBuilder.setSuccess(true);
            responseBuilder.setNodeId(copyEffect.getCopyNodeId());
        }
        catch (BusinessException e){
            log.error("通知失败：", e);
            responseBuilder.setSuccess(false);
        }
        responseObserver.onNext(responseBuilder.build());
        responseObserver.onCompleted();
    }

