        try {
            List<String> emailList = resultList.stream().map(UpdateUserNickResult::getEmail).collect(Collectors.toList());
            List<UserEntity> userList = iUserService.getByEmails(emailList);
            int successCount = 0;
            for(UpdateUserNickResult result : resultList){
