        }
        treeRes.forEach(res->{
                    GetTeamBranchResult result = GetTeamBranchResult.newBuilder().
                            setTeamId(res.getTeamId()).setTeamName(res.getTeamName()).
                            setParentId(res.getParentId()).setMemberCount(res.getMemberCount()).
