    @Override
    public void getArchiveRecordByDstId(GetArchiveRecordRequest request,
                                        StreamObserver<GetArchiveRecordResponse> responseObserver) {
        try {
            String dstId = request.getDstId();
            log.info("gRPC request: getArchiveRecordByDstId, dstId={}", dstId);

            // 调用原有服务
            List<DatasheetRecordArchiveEntity> entities =
                    datasheetRecordArchiveService.getArchiveRecordByDstId(dstId);

            // 转换为 gRPC 消息（只包含3个字段）
            List<DatasheetRecordArchive> records = entities.stream()
                    .map(this::convertToProto)
                    .collect(Collectors.toList());

            // 构建响应
            GetArchiveRecordResponse response = GetArchiveRecordResponse.newBuilder()
                    .addAllRecords(records)
                    .build();

            responseObserver.onNext(response);
            responseObserver.onCompleted();

        } catch (Exception e) {
            log.error("gRPC error: getArchiveRecordByDstId failed", e);
            responseObserver.onError(e);
        }
    }

    /**
